## Key Code

### 1. Event Handling (subagent-runner.ts)

No `processLine()` function. Events handled via `session.subscribe()` callback ‚Äî SDK pushes typed event objects, not raw JSON lines. Three event types handled:

```typescript
// Event type: "message_update" (text_delta)
if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
    output += event.assistantMessageEvent.delta;
    parseTextForFeed(feed, event.assistantMessageEvent.delta);
}

// Event type: "message_end"
if (event.type === "message_end") {
    if (event.message?.role === "assistant") {
        turns++;
        // ... completeCurrentStep, render, emitUpdate
    }
    // lint-guard custom messages
    if (event.message?.role === "custom" && event.message?.customType === "lint-guard") {
        // ...forward via onUpdate
    }
}

// Event type: "tool_execution_start"
if (event.type === "tool_execution_start") {
    const substepLabel = toolCallToSubstep(event.toolName, event.args);
    addSubstep(feed, substepLabel);
    // ... render, emitUpdate with details.tool
}

// Event type: "tool_execution_end"
if (event.type === "tool_execution_end") {
    // extract outputPreview, compress, truncate to 80 chars
    completeLastSubstep(feed, outputPreview);
    // ... render, emitUpdate
}
```

### 2. emitUpdate Pattern (subagent-runner.ts)

```typescript
onUpdate?.({
    content: [{ type: "text", text }],
    details: { specialist: specialist.name, status: "running" },
});
```

Called after every event type. Also called on 80ms interval via `renderTimer` for spinner animation.

### 3. toolCallToSubstep ‚Äî the formatter (activity-feed.ts, line ~276)

```typescript
export function toolCallToSubstep(toolName: string, input: any): string {
    const normalizePath = (p: string | undefined) => {
        if (!p) return "file";
        if (p.length > 50) {
            const parts = p.replace(/\/$/, "").split("/");
            return parts[parts.length - 1];
        }
        return p;
    };
    switch (toolName) {
        case "read":   return `Reading ${normalizePath(input?.path || input?.file_path)}`;
        case "bash":   return `Running: ${(input?.command || "...").slice(0, 40)}`;
        case "grep":   return `Searching: ${input?.pattern || "..."}`;
        case "find":   return `Finding: ${input?.pattern || "..."}`;
        case "edit":   return `Editing ${normalizePath(input?.path)}`;
        case "write":  return `Writing ${normalizePath(input?.path)}`;
        default:       return `Using ${toolName}`;
    }
}
```

### 4. addSubstep (activity-feed.ts, line ~256)

```typescript
export function addSubstep(state: ActivityFeedState, label: string): void {
    if (state.currentStep < 0 || state.steps.length === 0) {
        const implicitLabel = label.length > 60 ? label.slice(0, 57) + "..." : label;
        state.steps.push({ label: implicitLabel, completed: false, substeps: [], startTime: Date.now() });
        state.currentStep = 0;
    }
    if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
    const step = state.steps[state.currentStep];
    if (step.substeps.some((s) => s.label === label)) return;
    if (step.substeps.length >= MAX_FEED_SUBSTEPS) {
        step.substeps.shift();
    }
    step.substeps.push({ label, completed: false, startTime: Date.now() });
}
```

### 5. completeLastSubstep (activity-feed.ts, line ~287)

```typescript
export function completeLastSubstep(state: ActivityFeedState, outputPreview?: string): void {
    if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
    const step = state.steps[state.currentStep];
    if (step.substeps.length > 0) {
        const sub = step.substeps[step.substeps.length - 1];
        sub.completed = true;
        sub.endTime = Date.now();
        if (outputPreview) {
            sub.outputPreview = outputPreview;
        }
    }
}
```

### 6. Tool Calls Display (activity-feed.ts)

**Chat feed** (`renderActivityFeed`): shows completed substeps as `‚úì label (duration)`, active as `spinner label...`. Output preview **omitted** from chat feed for compactness.

**Plan panel** (`renderSubstepLines`): shows `‚úì label ‚Üí outputPreview` for completed, `‚ñ∂ label ‚Üí Running...` for active.

### 7. Types (types.ts)

```typescript
export interface Substep {
    label: string;
    completed: boolean;
    startTime?: number;
    endTime?: number;
    outputPreview?: string;
}
export interface Step {
    label: string;
    completed: boolean;
    substeps: Substep[];
    startTime?: number;
    endTime?: number;
}
export interface ActivityFeedState {
    goal: string;
    steps: Step[];
    currentStep: number;
    rawText: string;
    errored?: boolean;
    errorMessage?: string;
}
```

