Fix `isPathInScope` in scope-guard.ts to handle both absolute and relative paths in scope.json.

## Scope
- filesToModify: ["/Users/shivam94/.pi/agent/extensions/scope-guard.ts"]

## Problem
`isPathInScope` converts `filePath` to relative, but scope.json entries might be absolute. They never match.

## Current code (lines 62-70):
```ts
function isPathInScope(filePath: string, scope: Scope, cwd: string): boolean {
	const relPath = relative(cwd, filePath);
	const allApproved = [...scope.filesToModify, ...scope.filesToCreate];

	for (const approved of allApproved) {
		if (approved.endsWith("/*") && relPath.startsWith(approved.slice(0, -1))) return true;
		if (approved === relPath) return true;
		if (relPath.endsWith(`/${approved}`)) return true;
	}
	return false;
}
```

## Fix
Normalize both `relPath` and `approved` to relative paths:

```ts
function isPathInScope(filePath: string, scope: Scope, cwd: string): boolean {
	const relPath = relative(cwd, filePath);
	const allApproved = [...scope.filesToModify, ...scope.filesToCreate];

	for (const approved of allApproved) {
		// Normalize: if approved is absolute, convert to relative
		const approvedRel = isAbsolute(approved) ? relative(cwd, approved) : approved;

		if (approvedRel.endsWith("/*") && relPath.startsWith(approvedRel.slice(0, -1))) return true;
		if (approvedRel === relPath) return true;
		if (relPath.endsWith(`/${approvedRel}`)) return true;
	}
	return false;
}
```

Also add `isAbsolute` to the imports at the top:
```ts
import { relative, isAbsolute, join } from "path";
```

